formulas.formula:
Here's a complete formula sheet for CBSE Class 11 Accountancy - Recording of Transactions II in JSON format:

```json
[
  {
    "name": "Debit Note Formula",
    "formula": "Debit Note = Sales Return / Sales",
    "variables": {
      "Debit Note": "Value of debit note issued by the seller",
      "Sales Return": "Value of goods returned by the buyer",
      "Sales": "Original value of sale"
    },
    "units": "₹",
    "notes": "Used when a buyer returns goods to a seller and is given a debit note for the returned goods."
  },
  {
    "name": "Credit Note Formula",
    "formula": "Credit Note = Purchase Return / Purchase",
    "variables": {
      "Credit Note": "Value of credit note issued by the buyer",
      "Purchase Return": "Value of goods returned by the buyer",
      "Purchase": "Original value of purchase"
    },
    "units": "₹",
    "notes": "Used when a buyer returns goods to a seller and is given a credit note for the returned goods."
  },
  {
    "name": "Journal Voucher Formula",
    "formula": "Journal Voucher = Transaction Amount / 2",
    "variables": {
      "Journal Voucher": "Amount debited/credited in Journal Voucher",
      "Transaction Amount": "Total value of transaction"
    },
    "units": "₹",
    "notes": "Used when a transaction is recorded in a journal voucher."
  },
  {
    "name": "Accruals Formula",
    "formula": "Accruals = Uncollected Revenue / Period",
    "variables": {
      "Accruals": "Value of accruals",
      "Uncollected Revenue": "Revenue not yet collected",
      "Period": "Time period for which accruals are calculated"
    },
    "units": "₹",
    "notes": "Used when revenue is earned but not yet collected."
  },
  {
    "name": "Prepaid Expenses Formula",
    "formula": "Prepaid Expenses = Advance Payment / Period",
    "variables": {
      "Prepaid Expenses": "Value of prepaid expenses",
      "Advance Payment": "Amount paid in advance",
      "Period": "Time period for which prepaid expenses are calculated"
    },
    "units": "₹",
    "notes": "Used when expenses are paid in advance."
  },
  {
    "name": "Accumulated Depreciation Formula",
    "formula": "Accumulated Depreciation = Depreciation / Period",
    "variables": {
      "Accumulated Depreciation": "Total depreciation accumulated",
      "Depreciation": "Annual depreciation",
      "Period": "Time period for which depreciation is calculated"
    },
    "units": "₹",
    "notes": "Used when calculating accumulated depreciation over time."
  },
  {
    "name": "Depreciation Formula",
    "formula": "Depreciation = Cost - Residual Value / Period",
    "variables": {
      "Depreciation": "Annual depreciation",
      "Cost": "Original cost of asset",
      "Residual Value": "Value of asset at the end of its useful life",
      "Period": "Time period for which depreciation is calculated"
    },
    "units": "₹",
    "notes": "Used when calculating annual depreciation."
  }
]
```

